import React, { useState, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import './ProductPage.css';

// ── SIMULATED PRODUCT DETAILED REPOSITORY MODEL WITH UPDATED STRUCTURE ──
const MOCK_PRODUCT_DATABASE = {
  'prod-101': {
    name: "Custom Cloud Enterprise Resource Planning Premium Suite Pack",
    price: "₹45,000 / Module",
    description: "An end-to-end industry scale architecture deployment mapping accounting ledger automation, supply-chain routing logs, automated human asset pipelines, and telemetry performance tracking protocols.",
    // Specifications modeled as a dynamic object array to easily support backend-driven key-value configurations
    specs: [
      { label: "Sheet Material", value: "Color Coated Steel" },
      { label: "Sheet Thickness", value: "0.47 mm" },
      { label: "Thickness", value: "0.47mm, 0.50mm" },
      { label: "Profile Type", value: "Corrugated" }
    ],
    media: [
      'https://images.unsplash.com/photo-1551434678-e076c223a692?auto=format&fit=crop&w=800&q=80',
      'https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=800&q=80',
      'https://images.unsplash.com/photo-1504868584819-f8e8b4b6d7e3?auto=format&fit=crop&w=800&q=80',
      'https://images.unsplash.com/photo-1563013544-824ae1d704d3?auto=format&fit=crop&w=800&q=80',
      'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?auto=format&fit=crop&w=800&q=80'
    ]
  },
  'prod-102': {
    name: "E-Commerce Framework Implementation",
    price: "₹25,000 Startup Flat Rate",
    description: "Turnkey headless commerce architecture deployments engineered utilizing modern reactive component design blocks.",
    specs: [
      { label: "Framework Platform", value: "Next.js Headless v14" },
      { label: "Performance Metric", value: "Sub 200ms Server Side Render Generation" },
      { label: "Gateway Integration", value: "Integrated Local Payment Aggregations" }
    ],
    media: [
      'https://images.unsplash.com/photo-1563013544-824ae1d704d3?auto=format&fit=crop&w=800&q=80',
      'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?auto=format&fit=crop&w=800&q=80',
      'https://images.unsplash.com/photo-1551434678-e076c223a692?auto=format&fit=crop&w=800&q=80'
    ]
  }
};

const MOCK_SIDEBAR_FALLBACK = {
  company: {
    name: "Gv Solutions Private Limited",
    phone: "+91 84605 06156",
    email: "procure@gvsolutions.dev",
    address: "Surveyor Colony, Madurai, Tamil Nadu - 625007"
  },
  relatedCategories: [
    { id: 'cat-s1', name: 'SaaS Architecture Framework Enterprise Tools' },
    { id: 'cat-s2', name: 'Cloud Integration Providers' }
  ],
  relatedKeywords: ['CloudERP', 'NextJsHeadless', 'AutomatedOperations']
};

export default function ProductPage() {
  const { city, company, productId } = useParams();
  const navigate = useNavigate();
  
  const productEntity = MOCK_PRODUCT_DATABASE[productId] || MOCK_PRODUCT_DATABASE['prod-101'];
  const [selectedImgIdx, setSelectedImgIdx] = useState(0);
  
  // Track expanded text configurations for all items inside the similar products map layout
  const [expandedTextState, setExpandedTextState] = useState({});
  const thumbnailScrollContainerRef = useRef(null);

  // Manual scroll actions for handling carousel shift controls on x-axis
  const handleScrollThumbnails = (direction) => {
    if (thumbnailScrollContainerRef.current) {
      const scrollAmount = direction === 'left' ? -150 : 150;
      thumbnailScrollContainerRef.current.scrollBy({ left: scrollAmount, behavior: 'smooth' });
    }
  };

  const toggleTextExpansion = (id) => {
    setExpandedTextState(prev => ({ ...prev, [id]: !prev[id] }));
  };

  return (
    <div className="pdp-v3-root-wrapper">
      <div className="container pdp-v3-main-container">
        <div className="row pdp-v3-layout-row">

          {/* ── LEFT COLUMN AREA: MAIN PRODUCT PROFILE WORKSPACE ── */}
          <div className="col-lg-8 pdp-v3-scrollable-workspace">
            
            <div className="pdp-v3-breadcrumb-trail">
              {city || "Madurai"} &gt; {company || "Gv Solutions"} &gt; Products &gt; <span className="pdp-v3-breadcrumb-current">{productEntity.name}</span>
            </div>

            {/* Core Segment Split Card */}
            <div className="pdp-v3-master-display-card">
              <div className="row pdp-v3-asset-split-grid">
                
                {/* Visualizer Frame Box Segment (Switcher Dock with Move Buttons) */}
                <div className="col-md-6 pdp-v3-visualizer-cell">
                  <div className="pdp-v3-main-showcase-frame">
                    <img src={productEntity.media[selectedImgIdx]} alt={productEntity.name} className="pdp-v3-main-img" />
                  </div>
                  
                  {/* Horizontally Scrollable Row with Move Buttons at Both Sides */}
                  <div className="pdp-v3-carousel-controls-container">
                    <button type="button" className="pdp-v3-carousel-btn pdp-v3-carousel-btn-left" onClick={() => handleScrollThumbnails('left')}>
                      <i className="fas fa-chevron-left"></i>
                    </button>
                    
                    <div className="pdp-v3-thumbnail-x-scrollable-track" ref={thumbnailScrollContainerRef}>
                      {productEntity.media.map((src, idx) => (
                        <div 
                          key={idx} 
                          className={`pdp-v3-thumbnail-node${idx === selectedImgIdx ? ' pdp-v3-thumbnail-active' : ''}`}
                          onClick={() => setSelectedImgIdx(idx)}
                        >
                          <img src={src} alt={`Product snippet viewport ${idx + 1}`} />
                        </div>
                      ))}
                    </div>

                    <button type="button" className="pdp-v3-carousel-btn pdp-v3-carousel-btn-right" onClick={() => handleScrollThumbnails('right')}>
                      <i className="fas fa-chevron-right"></i>
                    </button>
                  </div>
                </div>

                {/* Technical Description Content Segment (Rearranged Order: Name, Price, Specs, Description) */}
                <div className="col-md-6 pdp-v3-details-cell">
                  <h1 className="pdp-v3-product-title">{productEntity.name}</h1>
                  <div className="pdp-v3-product-price">{productEntity.price}</div>
                  
                  <hr className="pdp-v3-divider" />
                  
                  {/* Dynamic Technical Specifications Layout Node */}
                  <h4 className="pdp-v3-section-subtitle">Technical Specifications</h4>
                  <div className="pdp-v3-specs-dynamic-table">
                    {productEntity.specs && productEntity.specs.length > 0 ? (
                      productEntity.specs.map((item, index) => (
                        <div key={index} className="pdp-v3-specs-row-node">
                          <span className="pdp-v3-spec-label">{item.label}:</span>
                          <span className="pdp-v3-spec-value">{item.value}</span>
                        </div>
                      ))
                    ) : (
                      <p className="pdp-v3-empty-fallback-text">No data specifications configured.</p>
                    )}
                  </div>

                  <h4 className="pdp-v3-section-subtitle">Product Description</h4>
                  <p className="pdp-v3-description-body">{productEntity.description}</p>
                  
                  <button className="pdp-v3-btn-action" onClick={() => alert('Requirement query transmission initialized.')}>
                    Procure Solution Specifications
                  </button>
                </div>

              </div>
            </div>

            {/* SIMILAR PRODUCTS SYSTEM FEED CONTAINER */}
            <div className="pdp-v3-master-display-card">
              <h3 className="pdp-v3-inner-card-heading">Similar Premium Architectural Solutions</h3>
              <div className="pdp-v3-similar-products-card-grid">
                {Object.keys(MOCK_PRODUCT_DATABASE).filter(id => id !== productId).map(id => {
                  const item = MOCK_PRODUCT_DATABASE[id];
                  const isExpanded = !!expandedTextState[id];
                  const charactersThreshold = 55;
                  const textNeedsTruncation = item.name.length > charactersThreshold;
                  
                  const renderTitle = () => {
                    if (!textNeedsTruncation || isExpanded) return item.name;
                    return `${item.name.substring(0, charactersThreshold)}...`;
                  };

                  return (
                    <div key={id} className="pdp-v3-similar-product-card-unit">
                      <div className="pdp-v3-similar-card-img-wrapper" onClick={() => { navigate(`/city/${city || 'madurai'}/${company || 'gvsolutions'}/product/${id}`); setSelectedImgIdx(0); }}>
                        <img src={item.media[0]} alt={item.name} />
                      </div>
                      <div className="pdp-v3-similar-card-content">
                        <div className="pdp-v3-similar-card-title-block">
                          <h5 className="pdp-v3-similar-card-name-text">
                            {renderTitle()}
                            {textNeedsTruncation && (
                              <button type="button" className="pdp-v3-text-toggle-inline-btn" onClick={(e) => { e.stopPropagation(); toggleTextExpansion(id); }}>
                                {isExpanded ? 'Less' : 'More'}
                              </button>
                            )}
                          </h5>
                        </div>
                        <div className="pdp-v3-similar-card-price-text">{item.price}</div>
                        <button type="button" className="pdp-v3-similar-card-view-btn" onClick={() => { navigate(`/city/${city || 'madurai'}/${company || 'gvsolutions'}/product/${id}`); setSelectedImgIdx(0); }}>
                          View Alternative
                        </button>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>

          </div>

          {/* ── RIGHT COLUMN AREA: FIXED STICKY SIDEBAR AREA ── */}
          <div className="col-lg-4 pdp-v3-sticky-sidebar-pane">
            <div className="pdp-v3-sidebar-modules-stack">
              
              {/* Context Module Box 1: Company Details Card with Contact info */}
              <div className="pdp-v3-sidebar-box-container">
                <h4 className="pdp-v3-sidebar-box-title">Company Profile Details</h4>
                <div className="pdp-v3-company-details-card-body">
                  <h5 className="pdp-v3-company-profile-name">{MOCK_SIDEBAR_FALLBACK.company.name}</h5>
                  <div className="pdp-v3-company-contact-item">
                    <i className="fas fa-phone-alt pdp-v3-contact-icon"></i>
                    <div>
                      <span className="pdp-v3-contact-label">Call Business:</span>
                      <a href={`tel:${MOCK_SIDEBAR_FALLBACK.company.phone}`} className="pdp-v3-contact-value-link">{MOCK_SIDEBAR_FALLBACK.company.phone}</a>
                    </div>
                  </div>
                  <div className="pdp-v3-company-contact-item">
                    <i className="fas fa-envelope pdp-v3-contact-icon"></i>
                    <div>
                      <span className="pdp-v3-contact-label">Email Queries:</span>
                      <a href={`mailto:${MOCK_SIDEBAR_FALLBACK.company.email}`} className="pdp-v3-contact-value-link">{MOCK_SIDEBAR_FALLBACK.company.email}</a>
                    </div>
                  </div>
                  <div className="pdp-v3-company-contact-item">
                    <i className="fas fa-map-marker-alt pdp-v3-contact-icon"></i>
                    <div>
                      <span className="pdp-v3-contact-label">Corporate Office:</span>
                      <span className="pdp-v3-contact-plaintext-address">{MOCK_SIDEBAR_FALLBACK.company.address}</span>
                    </div>
                  </div>
                </div>
              </div>

              {/* Context Module Box 2: Related Categories Layout */}
              <div className="pdp-v3-sidebar-box-container">
                <h4 className="pdp-v3-sidebar-box-title">Related Categories</h4>
                <div className="pdp-v3-sidebar-links-menu">
                  {MOCK_SIDEBAR_FALLBACK.relatedCategories.map((cat) => (
                    <div key={cat.id} className="pdp-v3-sidebar-link-row-item" onClick={() => alert(cat.name)}>
                      <span className="pdp-v3-link-row-text">{cat.name}</span>
                      <i className="fas fa-chevron-right pdp-v3-link-row-chevron"></i>
                    </div>
                  ))}
                </div>
              </div>

              {/* Context Module Box 3: Related Keywords Layout */}
              <div className="pdp-v3-sidebar-box-container">
                <h4 className="pdp-v3-sidebar-box-title">Related Keywords</h4>
                <div className="pdp-v3-sidebar-keywords-flex-box">
                  {MOCK_SIDEBAR_FALLBACK.relatedKeywords.map((kw, i) => (
                    <span key={i} className="pdp-v3-keyword-badge-node" onClick={() => alert(kw)}>#{kw}</span>
                  ))}
                </div>
              </div>

            </div>
          </div>

        </div>
      </div>
    </div>
  );
}
